import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";

function ViewApplications() {
  const [apps, setApps] = useState([]);
  const navigate = useNavigate();

  const loggedUser =
    JSON.parse(localStorage.getItem("loggedInUser")) || null;

  /* =========================
     LOAD APPLICATIONS
  ========================= */
  useEffect(() => {
    const stored =
      JSON.parse(localStorage.getItem("applications")) || [];

    // EMPLOYEE → only own applications
    if (loggedUser?.role === "employee") {
      const filtered = stored.filter(app =>
        app.email === loggedUser.username ||
        app.empId === loggedUser.empId
      );
      setApps(filtered);
    } else {
      // ADMIN → all applications
      setApps(stored);
    }
  }, [loggedUser]);

  /* =========================
     ADMIN STATUS UPDATE
  ========================= */
  const updateStatus = (id, status) => {
    if (loggedUser?.role !== "admin") return;

    const updated = apps.map(app =>
      app.id === id ? { ...app, status } : app
    );

    setApps(updated);
    localStorage.setItem("applications", JSON.stringify(updated));

    alert(`Application ${status}`);
  };

  /* =========================
     EMPLOYEE NAME
  ========================= */
  const getEmployeeName = (a) => {
    if (a.employeeName) return a.employeeName;

    const employees =
      JSON.parse(localStorage.getItem("employees")) || [];

    const emp = employees.find(e =>
      String(e.empId) === String(a.empId) ||
      String(e.email) === String(a.email)
    );

    if (emp) {
      const first = emp.firstName || "";
      const last = emp.lastName || "";
      return `${first} ${last}`.trim() || emp.name;
    }

    return "Unknown";
  };

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>
        {loggedUser?.role === "admin"
          ? "Job Applications (Admin)"
          : "My Job Applications"}
      </h2>

      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Employee</th>
            <th>Email</th>
            <th>Job Title</th>
            <th>Status</th>
            <th>Applied Date</th>
            {loggedUser?.role === "admin" && <th>Action</th>}
          </tr>
        </thead>

        <tbody>
          {apps.length === 0 ? (
            <tr>
              <td colSpan="7" style={{ textAlign: "center" }}>
                No Applications Found
              </td>
            </tr>
          ) : (
            apps.map((a, index) => (
              <tr key={a.id}>
                <td>{index + 1}</td>
                <td>{getEmployeeName(a)}</td>
                <td>{a.email}</td>
                <td>{a.jobTitle}</td>

                <td>
                  <span
                    style={{
                      padding: "6px 12px",
                      borderRadius: "6px",
                      fontWeight: "600",
                      color: "white",
                      background:
                        a.status === "Approved"
                          ? "green"
                          : a.status === "Rejected"
                          ? "red"
                          : "#64748b",
                    }}
                  >
                    {a.status}
                  </span>
                </td>

                <td>{a.appliedDate || "--"}</td>

                {/* ===== ADMIN ACTIONS ===== */}
                {loggedUser?.role === "admin" && (
                  <td style={{ display: "flex", gap: "10px" }}>

                    {/* 1️⃣ PENDING → APPROVE / REJECT */}
                    {a.status === "Pending" && (
                      <>
                        <button
                          style={{
                            background: "#16a34a",
                            color: "white",
                            padding: "6px 14px",
                            borderRadius: "6px",
                            border: "none",
                            cursor: "pointer",
                          }}
                          onClick={() => updateStatus(a.id, "Approved")}
                        >
                          Approve
                        </button>

                        <button
                          style={{
                            background: "#dc2626",
                            color: "white",
                            padding: "6px 14px",
                            borderRadius: "6px",
                            border: "none",
                            cursor: "pointer",
                          }}
                          onClick={() => updateStatus(a.id, "Rejected")}
                        >
                          Reject
                        </button>
                      </>
                    )}

                    {/* 2️⃣ APPROVED → OFFER LETTER */}
                    {a.status === "Approved" && (
                      <button
                        style={{
                          background: "#2563eb",
                          color: "white",
                          padding: "6px 14px",
                          borderRadius: "6px",
                          border: "none",
                          cursor: "pointer",
                        }}
                        onClick={() =>
                          navigate(
                            `/dashboard/recruitment/offer-letter/${a.id}`
                          )
                        }
                      >
                        Offer Letter
                      </button>
                    )}
                  </td>
                )}
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}

export default ViewApplications;
